import React, { useEffect, useState, useCallback, useRef } from 'react';
import {
  Card,
  Button,
  dispatchAppToast,
} from '@linm-soft-org/linm-web-common-components';
import {
  Title,
  Text,
  Tag,
  Modal,
  Popconfirm,
  Tooltip,
  Space,
  Spin,
} from '@/components/common';
import { fpcService } from '../../../services/fpc/service';
import type { CostCodeDto, CreateCostCodeDto, UpdateCostCodeDto } from '../../../services/fpc/types';
import { useAppDispatch } from '../../../store/hooks';
import styles from './CostCodePage.module.css';

const COST_TYPE_OPTIONS = [
  { value: 'COGS', label: 'Giá vốn hàng bán' },
  { value: 'Salary', label: 'Lương và nhân sự' },
  { value: 'Rent', label: 'Thuê mặt bằng' },
  { value: 'Utility', label: 'Điện nước và tiện ích' },
  { value: 'Logistics', label: 'Vận chuyển và hậu cần' },
  { value: 'OPEX', label: 'Chi phí hoạt động' },
  { value: 'Finance', label: 'Tài chính' },
];
const COMPARISON_OPTIONS = ['YoY', 'N-1'];
const GROUP_OPTIONS = ['Thu nhập', 'Chi phí'];
const PRIORITY_OPTIONS = ['Critical', 'High', 'Medium', 'Low'];

export default function CostCodePage() {
  const dispatch = useAppDispatch();
  const [data, setData] = useState<CostCodeDto[]>([]);
  const [loading, setLoading] = useState(true);
  const [modalOpen, setModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<CostCodeDto | null>(null);
  const [submitting, setSubmitting] = useState(false);

  // Form refs
  const codeRef = useRef<HTMLInputElement>(null);
  const nameRef = useRef<HTMLInputElement>(null);
  const parentCodeRef = useRef<HTMLInputElement>(null);
  const costTypeRef = useRef<HTMLSelectElement>(null);
  const comparisonRef = useRef<HTMLSelectElement>(null);
  const branchCodeRef = useRef<HTMLInputElement>(null);
  const descriptionRef = useRef<HTMLTextAreaElement>(null);
  const isActiveRef = useRef<HTMLInputElement>(null);
  const groupNameRef = useRef<HTMLSelectElement>(null);
  const priorityRef = useRef<HTMLSelectElement>(null);

  const fetchData = useCallback(async () => {
    setLoading(true);
    try {
      const result = await fpcService.getCostCodeList();
      setData(result);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const resetForm = () => {
    if (codeRef.current) codeRef.current.value = '';
    if (nameRef.current) nameRef.current.value = '';
    if (parentCodeRef.current) parentCodeRef.current.value = '';
    if (costTypeRef.current) costTypeRef.current.value = 'OPEX';
    if (comparisonRef.current) comparisonRef.current.value = 'N-1';
    if (branchCodeRef.current) branchCodeRef.current.value = '';
    if (descriptionRef.current) descriptionRef.current.value = '';
    if (isActiveRef.current) isActiveRef.current.checked = true;
    if (groupNameRef.current) groupNameRef.current.value = 'Chi phí';
    if (priorityRef.current) priorityRef.current.value = 'Medium';
  };

  const handleCreate = () => {
    setEditingItem(null);
    resetForm();
    setModalOpen(true);
  };

  const handleEdit = (item: CostCodeDto) => {
    setEditingItem(item);
    if (codeRef.current) codeRef.current.value = item.code;
    if (nameRef.current) nameRef.current.value = item.name;
    if (parentCodeRef.current) parentCodeRef.current.value = item.parentCode || '';
    if (costTypeRef.current) costTypeRef.current.value = item.costType;
    if (comparisonRef.current) comparisonRef.current.value = item.comparisonMethod;
    if (branchCodeRef.current) branchCodeRef.current.value = item.branchCode || '';
    if (descriptionRef.current) descriptionRef.current.value = item.description || '';
    if (isActiveRef.current) isActiveRef.current.checked = item.isActive;
    if (groupNameRef.current) groupNameRef.current.value = item.groupName || 'Chi phí';
    if (priorityRef.current) priorityRef.current.value = item.priority || 'Medium';
    setModalOpen(true);
  };

  const handleSubmit = async () => {
    if (!codeRef.current?.value || !nameRef.current?.value) return;

    setSubmitting(true);
    try {
      if (editingItem) {
        const dto: UpdateCostCodeDto = {
          name: nameRef.current.value,
          parentCode: parentCodeRef.current?.value || undefined,
          costType: costTypeRef.current?.value,
          comparisonMethod: comparisonRef.current?.value,
          branchCode: branchCodeRef.current?.value || undefined,
          description: descriptionRef.current?.value || undefined,
          isActive: isActiveRef.current?.checked,
          groupName: groupNameRef.current?.value,
          priority: priorityRef.current?.value,
        };
        await fpcService.updateCostCode(editingItem.id, dto);
        dispatchAppToast(dispatch, { message: 'Đã cập nhật mã chi phí', type: 'success' });
      } else {
        const dto: CreateCostCodeDto = {
          code: codeRef.current.value.toUpperCase(),
          name: nameRef.current.value,
          costType: costTypeRef.current?.value || 'OPEX',
          comparisonMethod: comparisonRef.current?.value || 'N-1',
          parentCode: parentCodeRef.current?.value || undefined,
          branchCode: branchCodeRef.current?.value || undefined,
          description: descriptionRef.current?.value || undefined,
          isActive: isActiveRef.current?.checked,
          groupName: groupNameRef.current?.value || 'Chi phí',
          priority: priorityRef.current?.value || 'Medium',
        };
        await fpcService.createCostCode(dto);
        dispatchAppToast(dispatch, { message: 'Đã tạo mã chi phí', type: 'success' });
      }
      setModalOpen(false);
      fetchData();
    } finally {
      setSubmitting(false);
    }
  };

  const handleDelete = async (id: string) => {
    await fpcService.deleteCostCode(id);
    dispatchAppToast(dispatch, { message: 'Đã xóa mã chi phí', type: 'success' });
    fetchData();
  };

  const renderTableRows = () => {
    if (loading) {
      return (
        <tr>
          <td colSpan={10} style={{ textAlign: 'center', padding: 24 }}><Spin /></td>
        </tr>
      );
    }
    if (data.length === 0) {
      return (
        <tr>
          <td colSpan={10} style={{ textAlign: 'center', padding: 24, color: '#999' }}>
            Chưa có mã chi phí nào
          </td>
        </tr>
      );
    }
    return data.map((record) => (
      <tr key={record.id}>
        <td className={styles.cellCode}><Text strong>{record.code}</Text></td>
        <td className={styles.cellName}>{record.name}</td>
        <td className={styles.cellType}><Tag>{record.costType}</Tag></td>
        <td className={styles.cellMethod}>{record.comparisonMethod}</td>
        <td className={styles.cellBranch}>{record.branchCode || '-'}</td>
        <td className={styles.cellActive}>
          {record.isActive ? <Tag color="green">Kích hoạt</Tag> : <Tag color="default">Tạm ngưng</Tag>}
        </td>
        <td className={styles.cellGroup}><Tag>{record.groupName || 'Chi phí'}</Tag></td>
        <td className={styles.cellPriority}>
          <Tag color={record.priority === 'Critical' ? 'red' : record.priority === 'High' ? 'orange' : record.priority === 'Medium' ? 'blue' : 'default'}>
            {record.priority || 'Medium'}
          </Tag>
        </td>
        <td className={styles.cellActions}>
          <Space>
            <Tooltip title="Sửa">
              <button className={styles.linkBtn} onClick={() => handleEdit(record)}>
                <i className="fas fa-edit" />
              </button>
            </Tooltip>
            <Popconfirm title="Xóa mã chi phí này?" onConfirm={() => handleDelete(record.id)}>
              <button className={`${styles.linkBtn} ${styles.linkBtnDanger}`}>
                <i className="fas fa-trash" />
              </button>
            </Popconfirm>
          </Space>
        </td>
      </tr>
    ));
  };

  const modalTitle = editingItem ? 'Sửa mã chi phí' : 'Tạo mã chi phí mới';

  return (
    <div className={styles.page}>
      <Title>Danh mục mã chi phí</Title>

      <Card style={{ marginBottom: 16 }}>
        <Button variant="primary" onClick={handleCreate}>
          <i className="fas fa-plus" style={{ marginRight: 6 }} />
          Thêm mã chi phí
        </Button>
      </Card>

      <table className={styles.table}>
        <thead>
          <tr>
            <th className={styles.thCode}>Mã CP</th>
            <th className={styles.thName}>Tên chi phí</th>
            <th className={styles.thType}>Loại CP</th>
            <th className={styles.thMethod}>PP đối soát</th>
            <th className={styles.thBranch}>Chi nhánh</th>
            <th className={styles.thActive}>Trạng thái</th>
            <th className={styles.thGroup}>Nhóm</th>
            <th className={styles.thPriority}>Mức độ</th>
            <th className={styles.thActions}></th>
          </tr>
        </thead>
        <tbody>{renderTableRows()}</tbody>
      </table>

      <Modal
        title={modalTitle}
        open={modalOpen}
        onOk={handleSubmit}
        onCancel={() => setModalOpen(false)}
        width={600}
        confirmLoading={submitting}
      >
        <div className={styles.formFields}>
          <div className={styles.inlineRow}>
            <div className={styles.fieldRow}>
              <label className={styles.fieldLabel}>
                Mã chi phí <span className={styles.required}>*</span>
              </label>
              <input
                ref={codeRef}
                className={styles.fieldInput}
                placeholder="VD: CP001"
                disabled={!!editingItem}
                required
              />
            </div>
            <div className={styles.fieldRow}>
              <label className={styles.fieldLabel}>
                Tên chi phí <span className={styles.required}>*</span>
              </label>
              <input ref={nameRef} className={styles.fieldInput} placeholder="VD: Chi phí nguyên liệu" required />
            </div>
          </div>
          <div className={styles.inlineRow}>
            <div className={styles.fieldRow}>
              <label className={styles.fieldLabel}>Loại chi phí</label>
              <select ref={costTypeRef} className={styles.fieldSelect} defaultValue="OPEX">
                {COST_TYPE_OPTIONS.map((opt) => (
                  <option key={opt.value} value={opt.value}>{opt.label}</option>
                ))}
              </select>
            </div>
            <div className={styles.fieldRow}>
              <label className={styles.fieldLabel}>Phương pháp đối soát</label>
              <select ref={comparisonRef} className={styles.fieldSelect} defaultValue="N-1">
                {COMPARISON_OPTIONS.map((opt) => (
                  <option key={opt} value={opt}>{opt === 'YoY' ? 'Cùng kỳ năm trước' : 'Tháng trước'}</option>
                ))}
              </select>
            </div>
          </div>
          <div className={styles.inlineRow}>
            <div className={styles.fieldRow}>
              <label className={styles.fieldLabel}>Mã cha</label>
              <input ref={parentCodeRef} className={styles.fieldInput} placeholder="VD: CP (nhóm)" />
            </div>
            <div className={styles.fieldRow}>
              <label className={styles.fieldLabel}>Chi nhánh</label>
              <input ref={branchCodeRef} className={styles.fieldInput} placeholder="Để trống = toàn công ty" />
            </div>
          </div>
          <div className={styles.inlineRow}>
            <div className={styles.fieldRow}>
              <label className={styles.fieldLabel}>Nhóm</label>
              <select ref={groupNameRef} className={styles.fieldSelect} defaultValue="Chi phí">
                {GROUP_OPTIONS.map((opt) => (
                  <option key={opt} value={opt}>{opt}</option>
                ))}
              </select>
            </div>
            <div className={styles.fieldRow}>
              <label className={styles.fieldLabel}>Mức độ ưu tiên</label>
              <select ref={priorityRef} className={styles.fieldSelect} defaultValue="Medium">
                {PRIORITY_OPTIONS.map((opt) => (
                  <option key={opt} value={opt}>{opt === 'Critical' ? 'Rất quan trọng' : opt === 'High' ? 'Quan trọng' : opt === 'Medium' ? 'Bình thường' : 'Thấp'}</option>
                ))}
              </select>
            </div>
          </div>
          <div className={styles.fieldRow}>
            <label className={styles.fieldLabel}>Mô tả</label>
            <textarea ref={descriptionRef} className={styles.fieldTextarea} rows={2} />
          </div>
          <div className={styles.fieldRow}>
            <label style={{ display: 'flex', alignItems: 'center', gap: 8, fontSize: 13, color: '#333' }}>
              <input ref={isActiveRef} type="checkbox" defaultChecked /> Kích hoạt
            </label>
          </div>
        </div>
      </Modal>
    </div>
  );
}
